urlset:
{{- /* Deduplicate pages by URL */ -}}
{{- $seen := dict -}}
{{- range .Site.AllPages -}}
  {{- $url := .Permalink -}}
  {{- if not (index $seen $url) -}}
    {{- $seen = merge $seen (dict $url true) -}}
    {{- /* Get the best date: Lastmod > Date > now */ -}}
    {{- $lastmod := .Lastmod -}}
    {{- if eq $lastmod.Year 1 -}}
      {{- $lastmod = .Date -}}
    {{- end -}}
    {{- if eq $lastmod.Year 1 -}}
      {{- $lastmod = now -}}
    {{- end -}}

      {{ .Permalink }}
      {{ $lastmod.Format "2006-01-02T15:04:05Z07:00" }}
      {{ cond (eq .Kind "page") "weekly" "daily" }}
      {{ cond (eq .Kind "page") "0.8" "0.5" }}

  {{- end -}}
{{- end -}}
